using namespace std;
#define size_b 256
unsigned char sbox[257] = { 0 };

//初始化s表
void init_sbox(unsigned char* key) {
    unsigned int i, j, k;
    int tmp;
    for (i = 0; i < size_b; i++) {
        sbox[i] = i;
    }
    j = k = 0;
    for (i = 0; i < size_b; i++) {
        tmp = sbox[i];
        j = (j + tmp + key[k]) % size_b;
        sbox[i] = sbox[j];
        sbox[j] = tmp;
        if (++k >= strlen((char*)key))k = 0;
    }
}

//加解密函数
void enc_dec(unsigned char* key, unsigned char* data) {
    int i, j, k, R, tmp;
    init_sbox(key);

    j = k = 0;
    for (i = 0; i < strlen((char*)data); i++) {
        j = (j + 1) % size_b;
        k = (k + sbox[j]) % size_b;

        tmp = sbox[j];
        sbox[j] = sbox[k];
        sbox[k] = tmp;

        R = sbox[(sbox[j] + sbox[k]) % size_b];

        data[i] ^= R;
    }
}

