```java
import com.sun.tools.attach.*;

import java.io.IOException;
import java.util.List;

public class hello {
    public static void main(String[] args) throws AgentLoadException, IOException, AttachNotSupportedException, AgentInitializationException {
        System.out.println("running JVM start");
        List<VirtualMachineDescriptor> list = VirtualMachine.list();
        String agent = "agentmain.jar";
        Integer i=0;
        String aim = "test.jar";//你的jar包
        System.out.println("[+]Finding: "+aim);
        System.out.println("[+]Agent jar: "+agent);

        for (VirtualMachineDescriptor vmd : list) {

            if (vmd.displayName().contains(aim)) {
                System.out.println(String.format("[+]find %s, process id %s", vmd.displayName(), vmd.id()));

                VirtualMachine virtualMachine = VirtualMachine.attach(vmd.id());  // 进程id号
                virtualMachine.loadAgent(agent);//你想要加载的agentmain包  loadAgent
                virtualMachine.detach();
                break;
            }

        }
    }
}
```

